import os
import json
import hashlib
from pathlib import Path
from typing import Optional

import numpy as np
from openai import OpenAI

# ── tiny in-process vector store (no external DB needed) ────────────────────

class VectorStore:
    """Simple in-memory vector database with cosine similarity search."""

    def __init__(self, persist_path: Optional[str] = None):
        self.documents: list[dict] = []  # {id, text, metadata, embedding}
        self.persist_path = persist_path
        if persist_path and Path(persist_path).exists():
            self._load()

    # -- CRUD ----------------------------------------------------------------

    def add(self, text: str, metadata: Optional[dict] = None, embedding: Optional[list[float]] = None):
        doc_id = hashlib.sha256(text.encode()).hexdigest()[:16]
        self.documents.append({
            "id": doc_id,
            "text": text,
            "metadata": metadata or {},
            "embedding": embedding,
        })
        return doc_id

    def search(self, query_embedding: list[float], top_k: int = 5) -> list[dict]:
        if not self.documents:
            return []
        q = np.array(query_embedding)
        scored = []
        for doc in self.documents:
            if doc["embedding"] is None:
                continue
            d = np.array(doc["embedding"])
            score = float(np.dot(q, d) / (np.linalg.norm(q) * np.linalg.norm(d) + 1e-10))
            scored.append({**doc, "score": score})
        scored.sort(key=lambda x: x["score"], reverse=True)
        return scored[:top_k]

    # -- persistence ----------------------------------------------------------

    def save(self):
        if self.persist_path:
            with open(self.persist_path, "w") as f:
                json.dump(self.documents, f)

    def _load(self):
        with open(self.persist_path) as f:
            self.documents = json.load(f)

    def __len__(self):
        return len(self.documents)


# ── document loaders ────────────────────────────────────────────────────────

def load_text_file(path: str) -> str:
    return Path(path).read_text(encoding="utf-8")


def load_pdf_file(path: str) -> str:
    """Best-effort PDF text extraction (requires PyPDF2)."""
    try:
        from PyPDF2 import PdfReader
        reader = PdfReader(path)
        return "\n".join(page.extract_text() or "" for page in reader.pages)
    except ImportError:
        raise ImportError("Install PyPDF2 to load PDF files:  pip install PyPDF2")


def load_document(path: str) -> str:
    ext = Path(path).suffix.lower()
    if ext == ".pdf":
        return load_pdf_file(path)
    elif ext in {".txt", ".md", ".csv", ".json", ".log", ".html", ".xml"}:
        return load_text_file(path)
    else:
        return load_text_file(path)  # fallback


# ── text chunker ────────────────────────────────────────────────────────────

def chunk_text(text: str, chunk_size: int = 500, overlap: int = 100) -> list[str]:
    """Split *text* into overlapping chunks of roughly *chunk_size* characters."""
    chunks: list[str] = []
    start = 0
    while start < len(text):
        end = start + chunk_size
        chunk = text[start:end]
        if chunk.strip():
            chunks.append(chunk.strip())
        start += chunk_size - overlap
    return chunks


# ── RAG system ──────────────────────────────────────────────────────────────

class RAGSystem:
    """
    End-to-end Retrieval Augmented Generation system.

    Uses OpenAI for embeddings and chat completions.
    Swap the client / model names to point at Azure OpenAI, Ollama, etc.
    """

    SYSTEM_PROMPT = (
        "You are an internal knowledge-base assistant. "
        "Answer the user's question using ONLY the context provided below. "
        "If the context does not contain enough information, say so honestly. "
        "Cite the source document when possible.\n\n"
        "### Retrieved Context\n{context}\n"
    )

    def __init__(
        self,
        openai_api_key: Optional[str] = None,
        embedding_model: str = "text-embedding-3-small",
        chat_model: str = "gpt-4o-mini",
        persist_path: str = "vector_store.json",
        chunk_size: int = 500,
        chunk_overlap: int = 100,
        top_k: int = 5,
    ):
        self.client = OpenAI(api_key=openai_api_key or os.getenv("OPENAI_API_KEY"))
        self.embedding_model = embedding_model
        self.chat_model = chat_model
        self.top_k = top_k
        self.chunk_size = chunk_size
        self.chunk_overlap = chunk_overlap
        self.store = VectorStore(persist_path=persist_path)
        self.conversation_history: list[dict] = []

    # -- embeddings -----------------------------------------------------------

    def _embed(self, texts: list[str]) -> list[list[float]]:
        """Get embeddings for a batch of texts."""
        response = self.client.embeddings.create(input=texts, model=self.embedding_model)
        return [item.embedding for item in response.data]

    # -- ingest ---------------------------------------------------------------

    def ingest_text(self, text: str, source: str = "unknown"):
        """Chunk a raw string and add it to the vector store."""
        chunks = chunk_text(text, self.chunk_size, self.chunk_overlap)
        if not chunks:
            return
        embeddings = self._embed(chunks)
        for chunk, emb in zip(chunks, embeddings):
            self.store.add(
                text=chunk,
                metadata={"source": source},
                embedding=emb,
            )
        self.store.save()
        print(f"  ✓ Ingested {len(chunks)} chunks from '{source}'")

    def ingest_file(self, path: str):
        """Load a file, chunk it, embed it, and store it."""
        print(f"Loading {path} …")
        text = load_document(path)
        self.ingest_text(text, source=Path(path).name)

    def ingest_directory(self, directory: str, extensions: Optional[set[str]] = None):
        """Recursively ingest every matching file under *directory*."""
        extensions = extensions or {".txt", ".md", ".pdf", ".csv", ".json", ".html"}
        for p in sorted(Path(directory).rglob("*")):
            if p.is_file() and p.suffix.lower() in extensions:
                self.ingest_file(str(p))

    # -- retrieval ------------------------------------------------------------

    def retrieve(self, query: str) -> list[dict]:
        """Return the top-k most relevant chunks for *query*."""
        q_emb = self._embed([query])[0]
        return self.store.search(q_emb, top_k=self.top_k)

    # -- generation -----------------------------------------------------------

    def _build_context_block(self, results: list[dict]) -> str:
        parts: list[str] = []
        for i, r in enumerate(results, 1):
            source = r["metadata"].get("source", "unknown")
            score = r.get("score", 0)
            parts.append(
                f"[Document {i} | source: {source} | relevance: {score:.3f}]\n{r['text']}"
            )
        return "\n\n---\n\n".join(parts)

    def query(self, user_question: str, include_history: bool = True) -> dict:
        """
        Full RAG pipeline:
        1. Retrieve relevant chunks.
        2. Build a prompt with all retrieved context.
        3. Call the LLM.
        4. Return answer + sources.
        """
        # 1. Retrieve
        results = self.retrieve(user_question)
        context_block = self._build_context_block(results) if results else "(No relevant documents found.)"

        # 2. Build messages
        system_msg = {"role": "system", "content": self.SYSTEM_PROMPT.format(context=context_block)}
        messages = [system_msg]

        if include_history:
            messages.extend(self.conversation_history)

        messages.append({"role": "user", "content": user_question})

        # 3. Call LLM
        response = self.client.chat.completions.create(
            model=self.chat_model,
            messages=messages,
            temperature=0.2,
            max_tokens=1024,
        )
        answer = response.choices[0].message.content

        # 4. Update conversation history
        self.conversation_history.append({"role": "user", "content": user_question})
        self.conversation_history.append({"role": "assistant", "content": answer})

        # Keep history bounded
        if len(self.conversation_history) > 20:
            self.conversation_history = self.conversation_history[-20:]

        sources = list({r["metadata"].get("source", "unknown") for r in results})

        return {
            "answer": answer,
            "sources": sources,
            "num_chunks_retrieved": len(results),
            "retrieved_chunks": [
                {"text": r["text"], "source": r["metadata"].get("source"), "score": r.get("score")}
                for r in results
            ],
        }

    def reset_conversation(self):
        self.conversation_history.clear()

    # -- stats ----------------------------------------------------------------

    def stats(self) -> dict:
        sources = set()
        for doc in self.store.documents:
            sources.add(doc["metadata"].get("source", "unknown"))
        return {
            "total_chunks": len(self.store),
            "unique_sources": sorted(sources),
            "embedding_model": self.embedding_model,
            "chat_model": self.chat_model,
        }


